import { useState } from "react";
import classes from "./BasicInput.module.css";

const ChatInput = (props) => {
  const [enteredValue, setEnteredValue] = useState("");

  let isEmpty = true;
  if (enteredValue !== "") {
    isEmpty = false;
  }

  // Sends message
  const submitHandler = () => {
    props.submitMessage(enteredValue);
    setEnteredValue("");
  };

  // Handles submission with enter key
  // const onKeydownHandler = (event) => {
  //   if (event.key === "Enter" && !event.shiftKey) {
  //     event.preventDefault();
  //     submitHandler();
  //     return;
  //   }
  // };

  // Handles input
  const onChangeHandler = (event) => {
    setEnteredValue(event.target.value);
  };

  return (
    <div className={classes["text-area"]}>
      <div className={classes["textbox"]}>
        {isEmpty && (
          <div
            className={`${classes["placeholder"]} ${classes["text-padding"]}`}
          >
            Message
          </div>
        )}
        <input
          onChange={onChangeHandler}
          value={enteredValue}
          className={`${classes["text"]} ${classes["text-padding"]}`}
        ></input>
      </div>
    </div>
  );
};

export default ChatInput;
